8	-- -------------------------------------------------------------------------------------------------
9	-- Testbench for both synchronous and asynchronous hard FIFOs.
10	-- -------------------------------------------------------------------------------------------------
11	
12	library ieee;
13	use ieee.std_logic_1164.all;
14	use ieee.numeric_std.all;
15	
16	library osvvm;
17	use osvvm.RandomPkg.RandomPType;
18	
19	library vunit_lib;
20	use vunit_lib.check_pkg.all;
21	use vunit_lib.queue_pkg.all;
22	use vunit_lib.run_pkg.all;
23	
24	library bfm;
25	use bfm.stall_bfm_pkg.stall_configuration_t;
26	
27	library common;
28	use common.types_pkg.all;
29	
30	use work.hard_fifo_pkg.all;
31	
32	
33	entity tb_hard_fifo is
34	  generic (
35	    data_width : positive;
36	    is_asynchronous : boolean;
37	    enable_output_register : boolean;
38	    read_clock_is_faster : boolean := false;
39	    read_stall_probability_percent : natural := 0;
40	    write_stall_probability_percent : natural := 0;
41	    runner_cfg : string
42	  );
43	end entity;
44	
45	architecture tb of tb_hard_fifo is
46	
47	  constant depth : positive := get_fifo_depth(target_width=>data_width);
48	  -- It appears that the synchronous FIFO can hold one extra word compared to asynchronous, in
49	  -- all configurations.
50	  constant fifo_capacity : positive :=
51	    depth + to_int(enable_output_register) + to_int(not is_asynchronous);
52	
53	  signal clk_read, clk_write : std_ulogic := '0';
54	
55	  signal read_ready, read_valid : std_ulogic := '0';
56	  signal write_ready, write_valid : std_ulogic := '0';
57	  signal read_data, write_data : std_ulogic_vector(data_width - 1 downto 0) := (others => '0');
58	
59	  signal has_gone_full_times, has_gone_empty_times : natural := 0;
60	
61	  constant read_stall_config : stall_configuration_t := (
62	    stall_probability => real(read_stall_probability_percent) / 100.0,
63	    min_stall_cycles => 1,
64	    max_stall_cycles => 3
65	  );
66	  constant write_stall_config : stall_configuration_t := (
67	    stall_probability => real(write_stall_probability_percent) / 100.0,
68	    min_stall_cycles => 1,
69	    max_stall_cycles => 3
70	  );
71	
72	  constant write_data_queue, read_data_queue : queue_t := new_queue;
73	
74	  signal stimuli_inactive, read_is_ready : std_ulogic := '0';
75	
76	begin
77	
78	  test_runner_watchdog(runner, 1 ms);
79	
80	
81	  ------------------------------------------------------------------------------
82	  clock_generation : if is_asynchronous generate
83	
84	    clocks : if read_clock_is_faster generate
85	      clk_read <= not clk_read after 2 ns;
86	      clk_write <= not clk_write after 3 ns;
87	    else  generate
88	      clk_read <= not clk_read after 3 ns;
89	      clk_write <= not clk_write after 2 ns;
90	    end generate;
91	
92	  else generate
93	    signal clk_base : std_ulogic := '0';
94	  begin
95	
96	    assert not read_clock_is_faster report "Should not set this generic for synchronous test";
97	
98	    clk_base <= not clk_base after 2 ns;
99	
100	    clk_read <= clk_base;
101	    clk_write <= clk_base;
102	
103	  end generate;
104	
105	
106	  ------------------------------------------------------------------------------
107	  main : process
108	
109	    variable rnd : RandomPType;
110	
111	    procedure wait_until_no_longer_in_reset is
112	    begin
113	      if is_asynchronous then
114	        wait until write_ready and rising_edge(clk_write);
115	
116	        for extra_wait_cycle in 0 to 6 loop
117	          wait until rising_edge(clk_write);
118	        end loop;
119	      end if;
120	    end procedure;
121	
122	    procedure run_read(count : natural) is
123	    begin
124	      read_is_ready <= '1';
125	      for read_idx in 0 to count - 1 loop
126	        wait until read_ready and read_valid and rising_edge(clk_read);
127	        check_equal(
128	          read_data,
129	          pop_std_ulogic_vector(read_data_queue),
130	          "read_idx=" & to_string(read_idx)
131	        );
132	      end loop;
133	      read_is_ready <= '0';
134	    end procedure;
135	
136	    procedure run_write(count : natural; wait_until_done : boolean) is
137	      variable data : std_ulogic_vector(write_data'range);
138	    begin
139	      for write_idx in 0 to count - 1 loop
140	        data := rnd.RandSLV(data'length);
141	        push(write_data_queue, data);
142	        push(read_data_queue, data);
143	      end loop;
144	
145	      if wait_until_done then
146	        wait until is_empty(write_data_queue) and rising_edge(clk_write);
147	        wait until stimuli_inactive and rising_edge(clk_write);
148	      end if;
